using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): check without throwing ---

// 2a. With the default reflection resolver every type resolves:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {found!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> returned false");

// 2b. Build options that have NO resolver at all, so nothing can resolve:
var empty = new JsonSerializerOptions { TypeInfoResolver = null };
empty.MakeReadOnly();           // lock the options so the result is deterministic

if (empty.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? notFound))
    Console.WriteLine($"Unexpected: got type info from empty resolver: {notFound!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> on resolver-less options => false (no exception!)");

public record Person(string Name, int Age);

